float calculateGrossSalary(float basicSalary) {
    float hra, da, grossSalary;
    if (basicSalary < 1500) {
        hra = 0.10 * basicSalary;
        da = 0.90 * basicSalary;
    } else {
        hra = 500.0;
        da = 0.98 * basicSalary;
    }
    grossSalary = basicSalary + hra + da;
    return grossSalary;
}

float calculateBill(int calls) {
    float bill = 0.0;
    if (calls <= 100) {
        bill = 200.0;
    } else if (calls <= 150) {
        bill = 200.0 + (calls - 100) * 0.60;
    } else if (calls <= 200) {
        bill = 200.0 + (50 * 0.60) + (calls - 150) * 0.50;
    } else {
        bill = 200.0 + (50 * 0.60) + (50 * 0.50) + (calls - 200) * 0.40;
    }
    return bill;
}

void solveQuadratic(double a, double b, double c) {
    double discriminant = b * b - 4 * a * c;
    if (discriminant > 0) {
        double root1 = (-b + sqrt(discriminant)) / (2 * a);
        double root2 = (-b - sqrt(discriminant)) / (2 * a);
        printf("Roots: %.2f, %.2f", root1, root2);
    } else if (discriminant == 0) {
        double root = -b / (2 * a);
        printf("Root: %.2f", root);
    } else {
        printf("No real roots");
    }
}

void calculateDivision(int marks[], int n) {
    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += marks[i];
    }
    float percentage = (float)sum / n;
    if (percentage >= 60.0) {
        printf("First division");
    } else if (percentage >= 50.0) {
        printf("Second division");
    } else if (percentage >= 40.0) {
        printf("Third division");
    } else {
        printf("Fail");
    }
}

