double calculatePower(double base, int exponent) {
    double result = 1.0;
    int abs_exponent = exponent < 0 ? -exponent : exponent;
    for (int i = 0; i < abs_exponent; i++) {
        result *= base;
    }
    if (exponent < 0) {
        return 1.0 / result;
    }
    return result;
}

int sumOfDigits(int n) {
    int sum = 0;
    if (n < 0) n = -n;
    while (n > 0) {
        sum += (n % 10);
        n /= 10;
    }
    return sum;
}

void printArmstrongNumbers(int start, int end) {
    for (int i = start; i <= end; i++) {
        int original = i;
        int sum = 0;
        int temp = i;
        while (temp > 0) {
            int digit = temp % 10;
            sum += (digit * digit * digit);
            temp /= 10;
        }
        if (sum == original) {
            printf("%d\n", original);
        }
    }
}

void printFibonacci(int n) {
    if (n <= 0) return;
    long long t1 = 0, t2 = 1, nextTerm;
    for (int i = 1; i <= n; ++i) {
        printf("%lld", t1);
        if (i < n) printf(" ");
        nextTerm = t1 + t2;
        t1 = t2;
        t2 = nextTerm;
    }
}

double computeLn2(int n) {
    double sum = 0.0;
    for (int i = 1; i <= n; i++) {
        if (i % 2 != 0) {
            sum += 1.0 / i;
        } else {
            sum -= 1.0 / i;
        }
    }
    return sum;
}

void printPatterns(int type) {
    int i, j, k;
    if (type == 1) {
        for (i = 0; i < 4; i++) { printf("**********\n"); }
    } else if (type == 2) {
        for (i = 1; i <= 5; i++) { for (j = 0; j < i; j++) printf("*"); printf("\n"); }
    } else if (type == 3) {
        for (i = 1; i <= 5; i++) { for (j = 0; j < 5 - i; j++) printf(" "); for (k = 0; k < i; k++) printf("*"); printf("\n"); }
    } else if (type == 4) {
        for (i = 1; i <= 5; i++) { for (j = 0; j < 5 - i; j++) printf(" "); for (k = 0; k < 2 * i - 1; k++) printf("*"); printf("\n"); }
    } else if (type == 5) {
        for (i = 1; i <= 5; i++) { for (j = 0; j < 5 - i; j++) printf(" "); for (k = 0; k < 2 * i - 1; k++) printf("%d", i); printf("\n"); }
    } else if (type == 6) {
        for (i = 1; i <= 5; i++) { for (j = 0; j < 5 - i; j++) printf(" "); for (k = i; k >= 1; k--) printf("%d", k); for (k = 2; k <= i; k++) printf("%d", k); printf("\n"); }
    }
}

double computeSine(double x, int n) {
    double sum = 0.0;
    double term = x;
    int sign = 1;
    for (int i = 1; i <= n; i += 2) {
        sum += sign * term;
        sign *= -1;
        term *= (x * x) / ((i + 1) * (i + 2));
    }
    return sum;
}

double compute_cosine(double x, int n) {
    double sum = 1.0;
    double term = 1.0;
    int sign = -1;
    for (int i = 2; i <= n; i += 2) {
        term *= (x * x) / ((double)i * (i - 1));
        sum += sign * term;
        sign *= -1;
    }
    return sum;
}

double calculateCompoundInterest(double p, double r, double t) {
