int binarySearch(int AR[], int target, int N) {
    int left = 0;
    int right = N - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (AR[mid] == target)
            return 1;
        if (AR[mid] < target)
            left = mid + 1;
        else
            right = mid - 1;
    }
    return 0;
}

void mergeSortedArrays(int A[], int M, int B[], int N, int C[]) {
    int i = 0;
    int j = N - 1;
    int k = 0;
    while (i < M && j >= 0) {
        if (A[i] < B[j]) {
            C[k++] = A[i++];
        } else {
            C[k++] = B[j--];
        }
    }
    while (i < M) {
        C[k++] = A[i++];
    }
    while (j >= 0) {
        C[k++] = B[j--];
    }
    for (int idx = 0; idx < M + N; idx++) {
        printf("%d ", C[idx]);
    }
}

int calculateStringLength(char str[]) {
    int length = 0;
    while (str[length] != '\0') {
        length++;
    }
    return length;
}

void printBackward(char* str) {
    int len = 0;
    while (str[len] != '\0') {
        len++;
    }
    for (int i = len - 1; i >= 0; i--) {
        printf("%c", str[i]);
    }
}

int countWords(char str[]) {
    int count = 0;
    int inWord = 0;
    for (int i = 0; str[i] != '\0'; i++) {
        if (str[i] == ' ' || str[i] == '\t' || str[i] == '\n') {
            inWord = 0;
        } else if (inWord == 0) {
            inWord = 1;
            count++;
        }
    }
    return count;
}

int compareStrings(char* str1, char* str2) {
    int i = 0;
    while (str1[i] != '\0' && str2[i] != '\0') {
        if (str1[i] != str2[i]) {
            return 0;
        }
        i++;
    }
    return (str1[i] == '\0' && str2[i] == '\0') ? 1 : 0;
}

int isPalindrome(char* str) {
    int len = 0;
    while (str[len] != '\0') len++;
    int i = 0;
    int j = len - 1;
    while (i < j) {
        if (str[i] != str[j]) return 0;
        i++;
        j--;
    }
    return 1;
}

void reverseString(char str[]) {
    int n = 0;
    while (str[n] != '\0') {
        n++;
    }
    for (int i = 0; i < n / 2; i++) {
        char temp = str[i];
        str[i] = str[n - i - 1];
        str[n - i - 1] = temp;
    }
    printf("%s", str);
}

void toLowercase(char str[]) {
    for (int i = 0; str[i] != '\0'; i++) {
        if (str[i] >= 'A' && str[i] <= 'Z') {
            str[i] = str[i] + ('a' - 'A');
        }
    }
    printf("%s", str);
}

void convertToUppercase(char str[]) {
    for (int i = 0; str[i] != '\0'; i++) {
        if (str[i] >= 'a' && str[i] <= 'z') {
            str[i] = str[i] - 32;
        }
    }
    printf("%s", str);
}

void performMatrixOperation(int A[10][10], int m, int n, int choice) {
    if (choice == 3) {
        int sum = 0;
        for (int i = 0; i < m; i++) for (int j = 0; j < n; j++) sum += A[i][j];
        printf("Sum of all elements: %d\n", sum);
    } else if (choice == 6) {
        printf("Transpose Matrix:\n");
        for (int j = 0; j < n; j++) {
            for (int i = 0; i < m; i++) printf("%d ", A[i][j]);
            printf("\n");
        }
    }
}

int leftDiagonalSum(int matrix[3][3], int n) {
    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += matrix[i][i];
    }
