void printMiddleElements(int arr[5][5], int n) {
    int mid = n / 2;
    printf("Middle Row : ");
    for (int i = 0; i < n; i++) {
        printf("%d%s", arr[mid][i], (i == n - 1) ? "" : " ");
    }
    printf("\nMiddle column : ");
    for (int i = 0; i < n; i++) {
        printf("%d%s", arr[i][mid], (i == n - 1) ? "" : " ");
    }
    printf("\n");
}

